// ── Circuit-board SVG pattern ─────────────────────────────────────────────────
function CircuitPattern() {
  return (
    <svg
      aria-hidden
      className="absolute inset-0 w-full h-full opacity-[0.04] pointer-events-none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <defs>
        <pattern id="circuit" x="0" y="0" width="80" height="80" patternUnits="userSpaceOnUse">
          <path d="M0 40h20M60 40h20M40 0v20M40 60v20" stroke="#FBBF24" strokeWidth="1" fill="none" />
          <circle cx="40" cy="40" r="3" fill="#FBBF24" />
          <circle cx="20" cy="40" r="2" fill="#FBBF24" />
          <circle cx="60" cy="40" r="2" fill="#FBBF24" />
          <circle cx="40" cy="20" r="2" fill="#FBBF24" />
          <circle cx="40" cy="60" r="2" fill="#FBBF24" />
          <path d="M20 40 Q30 40 30 30 Q30 20 40 20" stroke="#FBBF24" strokeWidth="0.6" fill="none" />
          <path d="M60 40 Q50 40 50 50 Q50 60 40 60" stroke="#FBBF24" strokeWidth="0.6" fill="none" />
        </pattern>
      </defs>
      <rect width="100%" height="100%" fill="url(#circuit)" />
    </svg>
  )
}

